steps.script:
var main = tree.root.get_node("Main")
var sc = main.shooting_controller
var phase = sc.current_phase
var ap = GameState.get_active_player()
# Find an active-player unit with 2+ distinct ranged weapon types.
var shooter_id = ""
var wtypes = []
for uid in GameState.state.units:
	var u = GameState.state.units[uid]
	if u.get("owner", 0) != ap:
		continue
	if u.get("models", []).is_empty():
		continue
	var wl = RulesEngine.get_unit_weapons(uid)
	var seen = {}
	for mid in wl:
		for w in wl[mid]:
			seen[w] = true
	if seen.size() >= 2:
		shooter_id = uid
		wtypes = seen.keys()
		break
if shooter_id == "":
	return "ERR no 2-weapon shooter"
var target_id = ""
for uid in GameState.state.units:
	var u = GameState.state.units[uid]
	if u.get("owner", 0) != ap and not u.get("models", []).is_empty():
		target_id = uid
		break
if target_id == "":
	return "ERR no target"
var shooter = GameState.state.units[shooter_id]
var target = GameState.state.units[target_id]
var bx = 880.0
var by = 1000.0
var si = 0
for m in shooter.models:
	m.position = {"x": bx, "y": by + si * 34}
	m.alive = true
	m["status"] = 2
	si += 1
shooter["status"] = 2
var ti = 0
for m in target.models:
	m.position = {"x": bx + 80, "y": by + ti * 34}
	m.alive = true
	ti += 1
GameState.state["players"][str(ap)]["cp"] = 5
var mids = []
for m in shooter.models:
	mids.append(m.id)
var m0 = mids[0]
var assigns = [
	{"weapon_id": wtypes[0], "target_unit_id": target_id, "model_ids": [m0]},
	{"weapon_id": wtypes[1], "target_unit_id": target_id, "model_ids": [m0]},
]
phase.active_shooter_id = shooter_id
phase.confirmed_assignments = assigns.duplicate(true)
sc.current_phase = phase
sc.call("_on_weapon_order_required", assigns)
return "OK shooter=" + shooter_id + " target=" + target_id + " cp=" + str(GameState.state.players[str(ap)].cp)

var d=tree.root.get_node_or_null("WeaponOrderDialog")
if d != null and d.reroll_row.visible and d.reroll_row.get_child_count() > 0:
	d._on_reroll_die_pressed(0)
	return "wound reroll used"
return "no wound reroll (already used or no wounds)"

var d=tree.root.get_node_or_null("WeaponOrderDialog")
if d != null:
	d._on_staged_continue_pressed()
	return "continued to saves"
return "dialog already closed"
